import { useMemo, useState } from "react";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";
import { formatCurrencyValue, useCurrencyVersion } from "@/lib/currency";

const FAQS = [
  { q: "How much does college cost on average?", a: "College costs vary widely by school type, location, housing, and aid. Tuition, fees, room, board, books, and personal expenses should all be included." },
  { q: "How do you save for college?", a: "Families often use monthly savings, 529 plans, scholarships, grants, work income, and student loans to cover college costs." },
  { q: "What is a 529 plan?", a: "A 529 plan is a tax-advantaged education savings account used for qualified education expenses." },
  { q: "How does financial aid work?", a: "Financial aid can include grants, scholarships, work-study, and loans. Need-based aid depends on family finances and school formulas." },
  { q: "Is college worth the cost?", a: "The answer depends on degree choice, school cost, aid, graduation odds, and expected earnings. Comparing total cost with likely income helps." },
];

const money = (v: number, d = 0) => formatCurrencyValue(Number.isFinite(v) ? v : 0, { maximumFractionDigits: d });
const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";

function projectedAnnual(current: number, yearsAway: number, inflation: number) {
  return current * Math.pow(1 + inflation / 100, yearsAway);
}

export default function CollegeCostCalculator() {
  useCurrencyVersion();
  const [annualCost, setAnnualCost] = useState(35000);
  const [yearsAway, setYearsAway] = useState(10);
  const [increase, setIncrease] = useState(5);
  const [collegeYears, setCollegeYears] = useState(4);
  const [aid, setAid] = useState(10000);
  const result = useMemo(() => {
    const rows = Array.from({ length: collegeYears }, (_, i) => {
      const year = yearsAway + i;
      const cost = projectedAnnual(annualCost, year, increase);
      return { year: i + 1, cost, aid, net: Math.max(0, cost - aid) };
    });
    const total = rows.reduce((s, r) => s + r.cost, 0);
    const net = rows.reduce((s, r) => s + r.net, 0);
    const months = Math.max(1, yearsAway * 12);
    return { rows, total, net, monthlySavings: net / months };
  }, [annualCost, yearsAway, increase, collegeYears, aid]);
  const comparison = [1, 3, 5, 10, 15, 18].map((years) => ({
    years,
    c20: projectedAnnual(20000, years, 5),
    c35: projectedAnnual(35000, years, 5),
    c55: projectedAnnual(55000, years, 5),
    total35: Array.from({ length: 4 }, (_, i) => projectedAnnual(35000, years + i, 5)).reduce((a, b) => a + b, 0),
  }));

  return (
    <>
      <SEOHead title="Free College Cost Calculator Online - Calculate Total College Education Cost Instantly | CalcHive" description="Free online college cost calculator. Calculate total projected college cost, monthly savings needed and impact of financial aid for any enrollment timeline instantly. 100% free, no signup required." canonical="/college-cost-calculator" keywords="free college cost calculator, college savings calculator free online, tuition cost calculator free, how much does college cost calculator free, education planning calculator free" category="Financial Calculators" breadcrumbName="Free College Cost Calculator Online" schemaType="WebApplication" schemaApplicationCategory="CalculatorApplication" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-sky-600 dark:text-sky-400 bg-sky-50 dark:bg-sky-950/50 px-3 py-1 rounded-full mb-4 inline-block">Financial</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free College Cost Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Project future college costs, expected financial aid, and required monthly savings.</p></div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-8">
            <div><label className="text-sm font-semibold text-foreground block mb-2">Current annual college cost</label><input type="number" value={annualCost} onChange={(e) => setAnnualCost(Number(e.target.value))} className={inputClass} /></div>
            <div><label className="text-sm font-semibold text-foreground block mb-2">Years until enrollment</label><input type="number" value={yearsAway} onChange={(e) => setYearsAway(Number(e.target.value))} className={inputClass} /></div>
            <div><label className="text-sm font-semibold text-foreground block mb-2">Annual cost increase (%)</label><input type="number" value={increase} onChange={(e) => setIncrease(Number(e.target.value))} className={inputClass} /></div>
            <div><label className="text-sm font-semibold text-foreground block mb-2">Years in college</label><input type="number" value={collegeYears} onChange={(e) => setCollegeYears(Number(e.target.value))} className={inputClass} /></div>
            <div className="sm:col-span-2"><label className="text-sm font-semibold text-foreground block mb-2">Expected financial aid per year</label><input type="number" value={aid} onChange={(e) => setAid(Number(e.target.value))} className={inputClass} /></div>
          </div>
          <div className="bg-gradient-to-br from-sky-500 to-sky-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Amount Needed to Save</p><p className="text-5xl sm:text-6xl font-black text-white">{money(result.net)}</p></div>
          <div className="grid grid-cols-1 sm:grid-cols-3 gap-3 mt-4"><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Projected total cost</p><p className="text-lg font-extrabold text-foreground">{money(result.total)}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Monthly savings</p><p className="text-lg font-extrabold text-foreground">{money(result.monthlySavings)}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Annual aid</p><p className="text-lg font-extrabold text-foreground">{money(aid)}</p></div></div>
        </section>
        <ShareButton />
        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Calculate Total College Cost and Savings Needed for Free</h2><p className="text-muted-foreground leading-relaxed">This free education cost planning tool projects each year of college, subtracts expected aid, and converts the remaining goal into monthly savings.</p>
          <h2 className="text-2xl font-bold text-foreground">How Tuition Inflation Affects Your College Savings Goal</h2>
          <div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold text-foreground mb-3">Projected College Cost With 5% Annual Increase</caption><thead className="bg-muted/60"><tr>{["Years Until College", "Current Annual Cost $20K", "Current Annual Cost $35K", "Current Annual Cost $55K", "4-Year Total at $35K"].map((h) => <th key={h} className="text-left py-3 px-3 font-semibold text-foreground">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{comparison.map((row) => <tr key={row.years}><td className="py-2.5 px-3 font-semibold">{row.years}</td><td className="py-2.5 px-3">{money(row.c20)}</td><td className="py-2.5 px-3">{money(row.c35)}</td><td className="py-2.5 px-3">{money(row.c55)}</td><td className="py-2.5 px-3">{money(row.total35)}</td></tr>)}</tbody></table></div>
          <h2 className="text-2xl font-bold text-foreground">Free Education Cost Planning Tool for Families</h2>
          <div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold text-foreground mb-3">Cost Projection Table</caption><thead className="bg-muted/60"><tr>{["College Year", "Projected Cost", "Financial Aid", "Net Cost"].map((h) => <th key={h} className="text-left py-3 px-3 font-semibold text-foreground">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{result.rows.map((row) => <tr key={row.year}><td className="py-2.5 px-3">{row.year}</td><td className="py-2.5 px-3">{money(row.cost)}</td><td className="py-2.5 px-3">{money(row.aid)}</td><td className="py-2.5 px-3">{money(row.net)}</td></tr>)}</tbody></table></div>
        </section>
        <section className="mb-8"><h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" /><RelatedTools exclude="/college-cost-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


